// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
// DDx-authored beads always round-trip through `bd import`. Empirically
// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
const MaxFieldBytes = 65535

// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
// need to preserve the full payload should persist it to a sidecar artifact
// and store a path reference in the field; this function is the defense-in-
// depth cap for code paths that don't. Returns the input unchanged when it
// fits; otherwise returns head+tail truncation with a byte-count marker.
func capFieldBytes(s string) string {
	if len(s) <= MaxFieldBytes {
		return s
	}
	// Reserve a marker that always fits; keep head heavy (2/3) so
	// human-readable context is preserved for the common short-rationale case.
	marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
	budget := MaxFieldBytes - len(marker)
	if budget <= 0 {
		return s[:MaxFieldBytes]
	}
	head := (budget * 2) / 3
	tail := budget - head
	return s[:head] + marker + s[len(s)-tail:]
}

// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
// cancel writes cancel-requested:true; the worker that honors the cancel writes
// cancel-honored:true alongside it.
const (
	ExtraCancelRequested = "cancel-requested"
	ExtraCancelHonored   = "cancel-honored"
)

// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
// if cancel-honored is already set the call is a silent no-op (the prior cancel
// was already consumed). Returns true when the marker is now set on the bead
// (either by this call or a prior one).
func (s *Store) RequestCancel(id string) (bool, error) {
	var set bool
	err := s.Update(id, func(b *Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		if isExtraTrue(b.Extra[ExtraCancelHonored]) {
			set = isExtraTrue(b.Extra[ExtraCancelRequested])
			return
		}
		b.Extra[ExtraCancelRequested] = true
		set = true
	})
	return set, err
}

// IsCancelRequested reports whether the bead carries an unconsumed cancel
// marker (cancel-requested:true and cancel-honored not yet set).
func (s *Store) IsCancelRequested(id string) (bool, error) {
	b, err := s.Get(id)
	if err != nil {
		return false, err
	}
	if b == nil || b.Extra == nil {
		return false, nil
	}
	if isExtraTrue(b.Extra[ExtraCancelHonored]) {
		return false, nil
	}
	return isExtraTrue(b.Extra[ExtraCancelRequested]), nil
}

// MarkCancelHonored sets Extra[cancel-honored]=true. Called by the worker once
// it has aborted at the next safe point in response to a cancel request.
func (s *Store) MarkCancelHonored(id string) error {
	return s.Update(id, func(b *Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		b.Extra[ExtraCancelHonored] = true
	})
}

func isExtraTrue(v any) bool {
	switch x := v.(type) {
	case bool:
		return x
	case string:
		return x == "true"
	}
	return false
}

func (s *Store) AppendEvent(id string, event BeadEvent) error {
	if event.CreatedAt.IsZero() {
		event.CreatedAt = time.Now().UTC()
	}
	// Defense in depth: cap every event body regardless of caller. The
	// reviewer write path separately persists the full stream to an artifact
	// and emits a <=512-byte body; this cap catches anything else.
	event.Body = capFieldBytes(event.Body)
	event.Summary = capFieldBytes(event.Summary)
	// Two storage shapes are possible here: inline Extra["events"] for active
	// beads, and a sidecar attachment for closed/archived beads (ADR-004
	// attachment model). When the bead has been externalized we append to the
	// sidecar and leave the row untouched aside from updated_at.
	var appendedToAttachment bool
	if err := s.Update(id, func(b *Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		if hasEventsAttachment(b) {
			appendedToAttachment = true
			return
		}
		var events []BeadEvent
		if raw, ok := b.Extra["events"]; ok {
			events = decodeBeadEvents(raw)
		}
		events = append(events, event)
		b.Extra["events"] = encodeEventsForExtra(events)
	}); err != nil {
		return err
	}
	if !appendedToAttachment {
		return nil
	}
	// Append to the sidecar under the store lock so concurrent readers and
	// writers see a consistent events log.
	return s.WithLock(func() error {
		existing, err := s.readEventsAttachment(id)
		if err != nil {
			return err
		}
		existing = append(existing, event)
		return s.writeEventsAttachment(id, existing)
	})
}

// Events returns the bead's evidence history in insertion order. Reads are
// transparent across storage shapes: inline Extra["events"] for active beads,
// or the externalized sidecar referenced by Extra[events_attachment] once the
// bead has been closed.
func (s *Store) Events(id string) ([]BeadEvent, error) {
	b, err := s.Get(id)
	if err != nil {
		return nil, err
	}
	events, err := s.eventsForBead(b)
	if err != nil {
		return nil, err
	}
	if len(events) == 0 {
		return []BeadEvent{}, nil
	}
	out := make([]BeadEvent, len(events))
	copy(out, events)
	return out, nil
}

// EventsByKind returns all events for a bead filtered by kind, in insertion order.
func (s *Store) EventsByKind(id, kind string) ([]BeadEvent, error) {
	all, err := s.Events(id)
	if err != nil {
		return nil, err
	}
	out := make([]BeadEvent, 0, len(all))
	for _, e := range all {
		if e.Kind == kind {
			out = append(out, e)
		}
	}
	return out, nil
}

func decodeBeadEvents(raw any) []BeadEvent {
	switch v := raw.(type) {
	case []BeadEvent:
		out := make([]BeadEvent, len(v))
		copy(out, v)
		return out
	case []any:
		out := make([]BeadEvent, 0, len(v))
		for _, item := range v {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			out = append(out, beadEventFromMap(m))
		}
		return out
	case []map[string]any:
		out := make([]BeadEvent, 0, len(v))
		for _, item := range v {
			out = append(out, beadEventFromMap(item))
		}
		return out
	default:
		return nil
	}
}

package bead

import (
	"fmt"
	"time"
)

// BeadsArchiveCollection is the logical collection name for archived beads.
// It is registered in the default registry alongside the active "beads"
// collection and is backed by .ddx/beads-archive.jsonl in the JSONL backend.
const BeadsArchiveCollection = "beads-archive"

// ArchivePolicy parameterises which closed beads are eligible to move from
// the active collection to the archive. Defaults match TD-027 §(b).
type ArchivePolicy struct {
	// Statuses lists the bead statuses that are eligible for archival.
	Statuses []string
	// MinAge is the minimum time since a bead was last updated/closed
	// before it may be archived.
	MinAge time.Duration
	// MinActiveCount is the floor on active-collection size below which
	// archival is a no-op. Set to 0 to archive regardless of size.
	MinActiveCount int
	// BatchSize caps how many records move per call.
	BatchSize int
}

// DefaultArchivePolicy returns the shipping defaults from TD-027 §(b).
func DefaultArchivePolicy() ArchivePolicy {
	return ArchivePolicy{
		Statuses:       []string{StatusClosed},
		MinAge:         30 * 24 * time.Hour,
		MinActiveCount: 2000,
		BatchSize:      500,
	}
}

// archivePartner returns a Store for the beads-archive collection rooted at
// the same .ddx directory as s. The partner reuses the shipping registry
// spec for "beads-archive" so file/lock paths are uniform.
func (s *Store) archivePartner() *Store {
	return NewStoreWithCollection(s.Dir, BeadsArchiveCollection)
}

// Archive moves eligible closed beads from this active store to the
// beads-archive partner. It applies preserve_dependencies semantics from
// TD-027 §(b): a closed bead that an open or in_progress bead still
// references is retained in the active collection so SD-004 queue
// derivation can resolve it without loading the archive.
//
// Returns the IDs that were moved.
func (s *Store) Archive(policy ArchivePolicy) ([]string, error) {
	if s.Collection != DefaultCollection {
		return nil, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
	}
	archive := s.archivePartner()

	var moved []string
	// Lock order is fixed: active first, archive second, per TD-027 §(b).
	err := s.WithLock(func() error {
		return archive.WithLock(func() error {
			activeBeads, _, rerr := s.readAllLatestRaw()
			if rerr != nil {
				return rerr
			}
			if policy.MinActiveCount > 0 && len(activeBeads) < policy.MinActiveCount {
				return nil
			}

			// preserve_dependencies: skip closed beads still referenced by
			// any non-closed bead's dependency list.
			referenced := make(map[string]bool)
			for _, b := range activeBeads {
				if b.Status == StatusClosed {
					continue
				}
				for _, dep := range b.DepIDs() {
					referenced[dep] = true
				}
			}

			now := time.Now().UTC()
			eligible := make(map[string]bool)
			var toMove []Bead
			for _, b := range activeBeads {
				if !containsString(policy.Statuses, b.Status) {
					continue
				}
				if referenced[b.ID] {
					continue
				}
				ts := b.UpdatedAt
				if raw, ok := b.Extra["closed_at"].(string); ok {
					if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
						ts = parsed
					}
				}
				if policy.MinAge > 0 && now.Sub(ts) < policy.MinAge {
					continue
				}
				toMove = append(toMove, b)
				if policy.BatchSize > 0 && len(toMove) >= policy.BatchSize {
					break
				}
			}
			if len(toMove) == 0 {
				return nil
			}

			archiveBeads, _, aerr := archive.readAllLatestRaw()
			if aerr != nil {
				return aerr
			}
			archiveByID := make(map[string]int, len(archiveBeads))
			for i, b := range archiveBeads {
				archiveByID[b.ID] = i
			}
			stamp := now.Format(time.RFC3339)
			for _, b := range toMove {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
				b.Extra["archived_at"] = stamp
				eligible[b.ID] = true
				if idx, ok := archiveByID[b.ID]; ok {
					archiveBeads[idx] = b
				} else {
					archiveByID[b.ID] = len(archiveBeads)
					archiveBeads = append(archiveBeads, b)
				}
			}

			// Step 7 of TD-027 mutation sequence: write archive first, then
			// active. A crash between the two leaves a duplicate in both
			// collections; merged-view reads in (e) hide that with
			// active-wins precedence.
			if werr := archive.WriteAll(archiveBeads); werr != nil {
				return fmt.Errorf("bead: write archive: %w", werr)
			}
			remaining := make([]Bead, 0, len(activeBeads)-len(toMove))
			for _, b := range activeBeads {
				if eligible[b.ID] {
					moved = append(moved, b.ID)
					continue
				}
				remaining = append(remaining, b)
			}
			if werr := s.WriteAll(remaining); werr != nil {
				return fmt.Errorf("bead: write active: %w", werr)
			}
			return nil
		})
	})
	if err != nil {
		return nil, err
	}
	return moved, nil
}

// GetWithArchive resolves a bead ID across the active collection and the
// archive partner, with active-wins precedence. This is the lookup the
// `ddx bead show` command uses so a closed-and-archived bead remains
// addressable by ID.
func (s *Store) GetWithArchive(id string) (*Bead, error) {
	if b, err := s.Get(id); err == nil {
		return b, nil
	}
	if s.Collection != DefaultCollection {
		return nil, fmt.Errorf("bead: not found: %s", id)
	}
	archive := s.archivePartner()
	b, err := archive.Get(id)
	if err != nil {
		return nil, fmt.Errorf("bead: not found: %s", id)
	}
	return b, nil
}

// ListWithArchive returns the union of active and archive beads filtered
// the same way as List. Active records take precedence over archive
// duplicates that may exist after an interrupted archive run.
func (s *Store) ListWithArchive(status, label string, where map[string]string) ([]Bead, error) {
	active, err := s.List(status, label, where)
	if err != nil {
		return nil, err
	}
	if s.Collection != DefaultCollection {
		return active, nil
	}
	archive := s.archivePartner()
	archived, err := archive.List(status, label, where)
	if err != nil {
		// Archive may not exist yet — treat as empty.
		return active, nil //nolint:nilerr
	}
	seen := make(map[string]bool, len(active))
	out := make([]Bead, 0, len(active)+len(archived))
	for _, b := range active {
		seen[b.ID] = true
		out = append(out, b)
	}
	for _, b := range archived {
		if seen[b.ID] {
			continue
		}
		out = append(out, b)
	}
	return out, nil
}

